        "People & Planet Positive sustainability strategy",
        "solar panels on stores",
        "circular economy product lines"
      ]
    },
    "Experiential": {
      "score": 7.0,
      "positioning": "The warehouse journey is a designed experience: one-way path, room vignettes, meatballs in the cafeteria, and the satisfaction of self-assembly.",
      "key_signals": [
        "one-way store layout",
        "Swedish meatballs as destination",
        "room vignettes at scale",
        "flat-pack assembly as ritual"
      ]
    },
    "Social": {
      "score": 5.0,
      "positioning": "Mass-market accessibility creates universal familiarity rather than exclusivity. IKEA ownership is a near-universal life-stage marker, particularly among young adults.",
      "key_signals": [
        "BILLY bookcase in 1-in-5 European homes",
        "student and first-home positioning",
        "IKEA hacking community",
        "broad demographic reach"
      ]
    },
    "Economic": {
      "score": 9.0,
      "positioning": "Price accessibility is the central value proposition and a structural design constraint. Every product starts with a target price point; design works backward from affordability.",
      "key_signals": [
        "price-first design process",
        "IKEA Family loyalty discounts",
        "visible price tags in every vignette",
        "annual IKEA catalogue as price reference"
      ]
    }
  }
}

